  {"name":"Scoops Homemade Ice Cream","group":"eat","cuisine":"Dessert","featured":false,"img":"","rating":"4.5","price":"$","tags":["homemade gelato","24 flavors","Starbucks drinks","next to Luau Larry's"],"cats":["family"],"desc":"Avalon's only house-made ice cream and gelato — two dozen rotating flavors (Rose Petal Raspberry, Kahului Espresso) that filled the void Big Olaf's left behind. Doubles as the town's Starbucks counter from 7am.","address":"501 Crescent Ave, Avalon, CA 90704","phone":"+13105100196","phoneLabel":"(310) 510-0196","website":"https://www.facebook.com/scoopscatalina/","menuUrl":"","reserve":"","hours":[[[7,18]],[[7,18]],[[7,18]],[[7,18]],[[7,18]],[[7,20]],[[7,20]]],"menu":[{"sec":"Scoops & Gelato","items":[{"n":"Homemade Ice Cream Scoop","p":"","d":"On a fresh waffle cone"},{"n":"Gelato Trio","p":"","d":"Three flavors in one cup"},{"n":"Chocolate-Covered Banana","p":"","d":"Old boardwalk classic"}]},{"sec":"Coffee Bar","items":[{"n":"Starbucks Espresso Drinks","p":"","d":"Full drink menu"},{"n":"Affogato","p":"","d":"Espresso over house gelato"},{"n":"Cold Brew","p":"","d":"For the beach walk"}]}]},
  {"name":"Lloyd's of Avalon","group":"eat","cuisine":"Dessert","featured":false,"img":"","rating":"4.5","price":"$","tags":["since 1934","saltwater taffy","taffy machine window","caramel apples"],"cats":["family"],"desc":"The candy institution on Crescent — watch the taffy puller work the window like it has for generations, then leave with a box of saltwater taffy and a caramel apple. Nobody's vacation is complete without it.","address":"315 Crescent Ave, Avalon, CA 90704","phone":"+13105107266","phoneLabel":"(310) 510-7266","website":"https://catalinacandy.com/","menuUrl":"https://catalinacandy.com/shop/","reserve":"","hours":[[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,21]],[[8,21]]],"menu":[{"sec":"Candy Counter","items":[{"n":"Saltwater Taffy","p":"","d":"Original recipe, handmade since 1941"},{"n":"Caramel Apple","p":"","d":"Hand-dipped, loaded toppings"},{"n":"House Fudge","p":"","d":"Cut thick by the slab"}]},{"sec":"More Sweets","items":[{"n":"Chocolate-Dipped Frozen Banana","p":"","d":"Boardwalk essential"},{"n":"Ice Cream Cones","p":"","d":"Simple scoops"},{"n":"Gift Boxes","p":"","d":"Taffy shipped home"}]}]},
  {"name":"Harbor Reef Restaurant & Saloon","group":"eat","cuisine":"American","featured":false,"img":"","rating":"4.2","price":"$$","tags":["Two Harbors","birthplace of Buffalo Milk","swordfish flag","only game in town"],"cats":["waterfront","patio","family"],"desc":"The one real restaurant in Two Harbors — if the swordfish flag flies on the pier, local swordfish is in the kitchen. The attached saloon is where the Buffalo Milk cocktail was invented 40+ years ago; bar opens at 3pm daily.","address":"1 Banning House Rd, Two Harbors, CA 90704","phone":"+13105104215","phoneLabel":"(310) 510-4215","website":"https://www.visitcatalinaisland.com/dining/harbor-reef-restaurant","menuUrl":"https://www.visitcatalinaisland.com/dining/harbor-reef-restaurant","reserve":"https://www.opentable.com/r/harbor-reef","hours":[[[8,16],[17,20]],[[8,16],[17,20]],[[8,16],[17,20]],[[8,16],[17,20]],[[8,16],[17,20]],[[8,16],[17,24]],[[8,16],[17,24]]],"menu":[{"sec":"Kitchen","items":[{"n":"Local Swordfish","p":"","d":"Summer catch — check the pier flag"},{"n":"BBQ Ribs","p":"","d":"Isthmus classic"},{"n":"Ahi Poke","p":"","d":"Saloon-side snack"}]},{"sec":"Saloon","items":[{"n":"Buffalo Milk","p":"","d":"Invented here — accept no substitutes"},{"n":"Draft Beer","p":"","d":"Cold after the ferry"},{"n":"Crab Cakes","p":"","d":"Bar bite favorite"}]}]},
  {"name":"Luau Larry's","group":"drink","kind":"place","cuisine":"Bar & Lounge","featured":false,"img":"","rating":"4.4","price":"$$","tags":["Wiki Wacker","wear the hat","live music","institution"],"cats":["patio","waterfront"],"desc":"THE Catalina bar. Order the Wiki Wacker, get the straw hat, and you're officially on island time — 30+ years of tropical drinks, swordfish tacos and live music steps from the sand. Kitchen's better than it needs to be.","address":"509 Crescent Ave, Avalon, CA 90704","phone":"+13105101919","phoneLabel":"(310) 510-1919","website":"https://luaularrys.com/","menuUrl":"https://luaularrys.com/menu/","reserve":"","hours":[[[11,25]],[[11,25]],[[11,25]],[[11,25]],[[11,25]],[[11,25]],[[10,25]]],"menu":[{"sec":"Libations","items":[{"n":"Wiki Wacker","p":"","d":"Rum, brandy, tropical juices — comes with the famous hat"},{"n":"Buffalo Milk","p":"","d":"Catalina's creamy classic"},{"n":"Caribbean Breeze","p":"","d":"Second-round favorite"}]},{"sec":"PuPus & Grub","items":[{"n":"Coconut Shrimp","p":"$19.95","d":"With spicy mango sauce"},{"n":"Swordfish Taco","p":"$7.50","d":"Local fish, single or by the plate"},{"n":"Cheeseburger","p":"","d":"Bar-solid"}]}]},
  {"name":"Marlin Club","group":"drink","kind":"place","cuisine":"Bar & Lounge","featured":false,"img":"","rating":"4.4","price":"$","tags":["oldest bar","since WWII","boat-bow bar","cash-strong pours"],"cats":[],"desc":"Avalon's oldest bar — built like a boat's bow by Merchant Marines during WWII, with Bud Upton's 1946 underwater mural still on the walls. Stiff drinks, pool, darts, zero pretension; open till 2am when the rest of town sleeps.","address":"108 Catalina Ave, Avalon, CA 90704","phone":"+13105100044","phoneLabel":"(310) 510-0044","website":"https://marlinclub.com/","menuUrl":"","reserve":"","hours":[[[10,26]],[[10,26]],[[10,26]],[[10,26]],[[10,26]],[[10,26]],[[10,26]]],"menu":[{"sec":"Drinks","items":[{"n":"Fresh Lemon Drop","p":"","d":"Made with real juice — house specialty"},{"n":"Bloody Mary","p":"","d":"Morning-after standard"},{"n":"Well Cocktails","p":"","d":"Strong and honest"}]},{"sec":"The Scene","items":[{"n":"Bottled & Draft Beer","p":"","d":"Limited but cold"},{"n":"Pool & Darts","p":"","d":"Free entertainment"},{"n":"Live Music Nights","p":"","d":"Check the chalkboard"}]}]},
  {"name":"Chi Chi Club","group":"drink","kind":"place","cuisine":"Nightlife","featured":false,"img":"","rating":"4.0","price":"$","tags":["only nightclub","dance floor","DJs & live bands","late late"],"cats":[],"desc":"The island's only real nightclub and basically the only thing open past midnight — DJs, live bands, a proper dance floor and cheap, fast drinks. It gets going late and gets loose; that's the assignment.","address":"105 Sumner Ave, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://www.instagram.com/thecatalinachi/","menuUrl":"","reserve":"","hours":[[[20,26]],[[20,26]],[[20,24]],[[20,24]],[[20,26]],[[20,26]],[[20,26]]],"menu":[{"sec":"Bar","items":[{"n":"Well Drinks","p":"","d":"Cheap and quick"},{"n":"Shots","p":"","d":"The Chi Chi currency"},{"n":"Bottled Beer","p":"","d":"Buckets for the table"}]},{"sec":"The Night","items":[{"n":"DJ Sets","p":"","d":"Weekends in season"},{"n":"Live Bands","p":"","d":"Rotating schedule"},{"n":"VIP Service","p":"","d":"Email ahead for groups"}]}]},
  {"name":"The Locker Room","group":"drink","kind":"place","cuisine":"Bar & Lounge","featured":false,"img":"","rating":"4.4","price":"$","tags":["Cubs history","locals only vibe","pool tables","BYO food"],"cats":[],"desc":"JL's to the regulars — a sports bar inside the actual locker room the Chicago Cubs used for spring training on the island. Generous pours, fair prices, two pool tables, and you can bring in pizza from next door.","address":"126 Sumner Ave, Avalon, CA 90704","phone":"","phoneLabel":"","website":"","menuUrl":"","reserve":"","hours":[[],[[10,26]],[[10,26]],[[10,26]],[[10,26]],[[10,26]],[[10,26]]],"menu":[{"sec":"Drinks","items":[{"n":"Draft Beer","p":"","d":"Cheapest honest pint downtown"},{"n":"Well Cocktails","p":"","d":"Famously generous pours"},{"n":"Shots & Chasers","p":"","d":"Game-day fuel"}]},{"sec":"House Rules","items":[{"n":"BYO Food","p":"","d":"Have Antonio's deliver pizza to your stool"},{"n":"Every Game On","p":"","d":"Wall of TVs"},{"n":"Pool & Darts","p":"","d":"Evenings get competitive"}]}]},
  {"name":"Catalina Island Brew House","group":"drink","kind":"place","cuisine":"Brewery","featured":false,"img":"","rating":"4.4","price":"$$","tags":["only island brewery","coffee till 4","small batch","pizza & pints"],"cats":["patio","breakfast"],"desc":"Coffee and pastries from 7am, house-brewed beer and pizza in the afternoon — Catalina's only microbrewery, turning out one or two barrels a week of genuinely small-batch beer. The patio is prime Crescent Ave people-watching.","address":"417 Crescent Ave, Avalon, CA 90704","phone":"+13103398085","phoneLabel":"(310) 339-8085","website":"https://www.catalinabrewhouse.com/","menuUrl":"https://www.catalinabrewhouse.com/","reserve":"","hours":[[[7,16]],[[7,16]],[[7,16]],[[7,16]],[[7,16]],[[7,19]],[[7,19]]],"menu":[{"sec":"Taps","items":[{"n":"House Small-Batch Pints","p":"","d":"~250 pints per batch, rotating styles"},{"n":"Beer Flight","p":"","d":"Try what's fresh"},{"n":"Guest Ciders","p":"","d":"For the non-beer crowd"}]},{"sec":"Cafe","items":[{"n":"Espresso Drinks","p":"","d":"The morning half of the identity"},{"n":"Pastries","p":"","d":"Fresh case daily"},{"n":"Pizza","p":"","d":"Afternoon pairing with pints"}]}]},
  {"name":"Topside by NDMK","group":"drink","kind":"place","cuisine":"Bar & Lounge","featured":false,"img":"","rating":"4.2","price":"$$","tags":["rooftop","harbor views","craft cocktails","NDMK sister spot"],"cats":["waterfront","patio","breakfast"],"desc":"Avalon's rooftop — NDMK's sister spot at the far end of Crescent with harbor views, handcrafted cocktails, oysters and tap beers from breakfast through sunset. The view at golden hour is the whole pitch.","address":"708 Crescent Ave, Avalon, CA 90704","phone":"+13105108599","phoneLabel":"(310) 510-8599","website":"https://topsidebyndmk.com/","menuUrl":"https://topsidebyndmk.com/","reserve":"https://www.opentable.com/r/topside-by-ndmk-avalon","hours":[[[8,21]],[[8.5,20]],[[8.5,20]],[[8.5,20]],[[8.5,20]],[[8.5,21]],[[8,21]]],"menu":[{"sec":"Rooftop Bar","items":[{"n":"Handcrafted Cocktails","p":"","d":"Classics and house originals"},{"n":"Tap Beers & Ciders","p":"","d":"Rotating local lineup"},{"n":"Sunset Spritzes","p":"","d":"Timed to the view"}]},{"sec":"Raw & Snacks","items":[{"n":"Oysters","p":"","d":"A quiet bargain up here"},{"n":"Fish Tacos","p":"$22","d":"Same local fish as NDMK downstairs"},{"n":"Flatbread","p":"","d":"Built for sharing over drinks"}]}]},
  {"name":"Catalina Casino","group":"do","kind":"place","cuisine":"Attraction","featured":false,"img":"","rating":"4.7","price":"$$","tags":["Historic Landmark","Art Deco","Guided Tours","Date Night","Iconic"],"cats":["waterfront"],"desc":"Avalon's 1929 Art Deco crown jewel — never a gambling hall, but home to the world's largest circular ballroom. Book the walking or behind-the-scenes tour; times sell out on cruise-ship days.","address":"1 Casino Way, Avalon, CA 90704","phone":"(877) 778-8322","phoneLabel":"Book Tours","website":"https://www.visitcatalinaisland.com/things-to-do/catalina-casino","menuUrl":"https://www.visitcatalinaisland.com/things-to-do/catalina-casino-general-admission","reserve":"https://www.visitcatalinaisland.com/things-to-do/catalina-casino","hours":[[[10,16]],[[10,16]],[[10,16]],[[10,16]],[[10,16]],[[10,16]],[[10,16]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Discover the Casino Tour (45–50 min)","p":"$20","d":"Guided walk through the theatre and ballroom; departs ~11:45am & 2:30pm"},{"n":"Behind-the-Scenes / VIP Backstage Tour (90 min)","p":"$38.50","d":"Stage, dressing rooms, projection booth and Wrigley family room"},{"n":"Self-Guided General Admission","p":"$19.50","d":"Roam the landmark at your own pace; children/seniors/military $17.50"}]}]},
  {"name":"Avalon Theatre (Casino Movie Palace)","group":"do","kind":"place","cuisine":"Movies & Shows","featured":false,"img":"","rating":"4.6","price":"$","tags":["Historic Cinema","Pipe Organ","First-Run Films","Date Night"],"cats":["waterfront"],"desc":"First-run movies inside the Casino's 1,184-seat 1929 movie palace, with hand-painted Beckman murals. Catch the vintage Page pipe organ played before Friday–Saturday shows; schedule thins outside summer.","address":"1 Casino Way, Avalon, CA 90704","phone":"(310) 510-0179","phoneLabel":"Showtimes","website":"https://www.visitcatalinaisland.com/things-to-do/avalon-theatre","menuUrl":"https://www.visitcatalinaisland.com/things-to-do/avalon-theatre","reserve":"","hours":[[[18,21.5]],[[18,21.5]],[[18,21.5]],[[18,21.5]],[[18,21.5]],[[18,21.5]],[[18,21.5]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Feature film (nightly ~6:30pm)","p":"","d":"Current and classic films in a landmark auditorium"},{"n":"Pipe organ prelude","p":"","d":"Live organ performance ~1 hour before Fri & Sat films"},{"n":"Live performances & events","p":"","d":"Occasional concerts and special screenings"}]}]},
  {"name":"Glass Bottom Boat Voyage","group":"do","kind":"place","cuisine":"Boating & Water","featured":false,"img":"","rating":"4.4","price":"$","tags":["Classic Catalina","Kids Love It","Lovers Cove","Family Fun"],"cats":["waterfront","family"],"desc":"The 45-minute classic since the 1890s — glide from the Green Pleasure Pier to Lovers Cove and watch garibaldi swarm under the glass. Seasonal night trips chase Catalina's famous flying fish.","address":"Green Pleasure Pier, Float B, Avalon, CA 90704","phone":"(877) 778-8322","phoneLabel":"Book","website":"https://www.visitcatalinaisland.com/things-to-do","menuUrl":"https://www.catalinatours.com/tour/glass-bottom-boat-voyage/","reserve":"https://www.visitcatalinaisland.com/things-to-do","hours":[[[10,19]],[[10,19]],[[10,19]],[[10,19]],[[10,19]],[[10,19]],[[10,19]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Daytime voyage (45 min)","p":"$29","d":"Lovers Cove kelp forest with captain's ecology commentary"},{"n":"Night voyage (seasonal)","p":"","d":"Summer evenings — spotlights draw flying fish and nocturnal sea life"},{"n":"Kids' fare","p":"","d":"Discounted child pricing; free cancellation to 24 hrs"}]}]},
  {"name":"Nautilus Semi-Submarine (Catalina Adventure Tours)","group":"do","kind":"place","cuisine":"Boating & Water","featured":false,"img":"","rating":"4.3","price":"$$","tags":["Semi-Submersible","Underwater Views","Family Fun","Lovers Cove"],"cats":["waterfront","family"],"desc":"The yellow semi-sub dives you six feet below the surface at Lovers Cove, with round portholes and fish feeders at every window. Departs the Green Pier several times daily — easier on kids than snorkeling.","address":"Green Pleasure Pier, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://catalinaadventuretours.com/","menuUrl":"https://catalinaadventuretours.com/nautilus-semi-submarine-excursion.html","reserve":"https://catalinaadventuretours.com/ocean-excursions.html","hours":[[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Nautilus Semi-Sub (adult)","p":"$48.50","d":"45-min undersea expedition to Lovers Cove marine preserve"},{"n":"Child (3–11)","p":"$38.50","d":"Seniors $40.50, military $40, under 2 ~$6"},{"n":"Sea View Glass Bottom Boat","p":"","d":"Same operator's classic glass-bottom alternative from the pier"}]}]},
  {"name":"Catalina Zipline Eco Tour","group":"do","kind":"place","cuisine":"Attraction","featured":false,"img":"","rating":"4.7","price":"$$$","tags":["Adrenaline","Ocean Views","Eco Tour","Date Night","Booking Required"],"cats":[],"desc":"Five lines dropping 600 feet down Descanso Canyon to the beach at up to 45 mph — the island's biggest thrill, running daily in 2026. Book ahead; riders must be 55\"+ tall and 80–240 lbs.","address":"1 St Catherine Way (Descanso Canyon), Avalon, CA 90704","phone":"(877) 778-6457","phoneLabel":"Reservations","website":"https://www.visitcatalinaisland.com/things-to-do/catalina-island-zip-line-eco-tour","menuUrl":"https://www.visitcatalinaisland.com/things-to-do/zipline-tour-requirements","reserve":"https://www.visitcatalinaisland.com/things-to-do/catalina-island-zip-line-eco-tour","hours":[[[9.33,16.33]],[[9.33,16.33]],[[9.33,16.33]],[[9.33,16.33]],[[9.33,16.33]],[[9.33,16.33]],[[9.33,16.33]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Zipline Eco Tour (~2 hrs)","p":"$139.95","d":"Five ziplines through Descanso Canyon; weekend/holiday ~$149"},{"n":"Ship & Zip package","p":"","d":"Ferry + zipline combo deals via Catalina Island Company"},{"n":"Eco narration","p":"","d":"Guides cover island ecology at each platform between lines"}]}]},
  {"name":"Catalina Aerial Adventure","group":"do","kind":"place","cuisine":"Games & Fun","featured":false,"img":"","rating":"4.5","price":"$$","tags":["Ropes Course","Family Fun","Self-Paced","Treetop"],"cats":["family"],"desc":"Five self-paced ropes courses (beginner to advanced) of ladders, log bridges and balance beams in the eucalyptus grove next to Descanso Beach. Plan ~90 minutes; closed-toe shoes and 55\" height required.","address":"1 St Catherine Way (Descanso Canyon), Avalon, CA 90704","phone":"(877) 778-8322","phoneLabel":"Book","website":"https://www.visitcatalinaisland.com/things-to-do/catalina-aerial-adventure","menuUrl":"https://www.visitcatalinaisland.com/things-to-do/catalina-aerial-adventure","reserve":"https://www.visitcatalinaisland.com/things-to-do/catalina-aerial-adventure","hours":[[[11,15]],[[11,15]],[[11,15]],[[11,15]],[[11,15]],[[11,15]],[[11,15]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"All-course access (~90 min)","p":"","d":"5 courses: 2 beginner, 2 intermediate, 1 advanced"},{"n":"Aerial Adventure at Dark","p":"","d":"Seasonal evening climbs under the lights"},{"n":"Combo with zipline","p":"","d":"Discounted when bundled with the Zipline Eco Tour"}]}]},
  {"name":"Bison Expedition (Interior Eco Tour)","group":"do","kind":"place","cuisine":"Attraction","featured":false,"img":"","rating":"4.6","price":"$$$","tags":["Wild Bison","Open-Air Hummer","Island Interior","Eco Tour","Booking Required"],"cats":["family"],"desc":"Two hours in an open-air biofuel Hummer through Middle Ranch and Cape Canyon hunting for the island's famous bison herd, descendants of a 1924 movie shoot. Sightings are wild-animal luck, but guides usually deliver.","address":"Tour Plaza, 100 Sumner Ave, Avalon, CA 90704","phone":"(877) 778-8322","phoneLabel":"Book","website":"https://www.visitcatalinaisland.com/things-to-do/bison-expedition","menuUrl":"https://www.catalinatours.com/tour/bison-expedition/","reserve":"https://www.visitcatalinaisland.com/things-to-do/bison-expedition","hours":[[[9,15]],[[9,15]],[[9,15]],[[9,15]],[[9,15]],[[9,15]],[[9,15]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Bison Expedition (2 hrs)","p":"","d":"12-passenger eco Hummer into Middle Canyon & Cape Canyon"},{"n":"Cape Canyon Expedition with lunch","p":"","d":"Longer off-road interior tour incl. Airport in the Sky stop"},{"n":"Conservancy Eco Tour alternative","p":"","d":"Catalina Conservancy runs its own official Wildlands tours"}]}]},
  {"name":"Catalina Museum for Art & History","group":"do","kind":"place","cuisine":"Attraction","featured":false,"img":"","rating":"4.5","price":"$","tags":["Local History","Art Exhibits","Rainy Day","Date Night"],"cats":[],"desc":"Ackerman-designed galleries covering Wrigley-era Avalon, big-band Casino nights and Catalina pottery, plus rotating art shows 3–4 times a year. Closed Mondays; kids 15 and under free.","address":"217 Metropole Ave, Avalon, CA 90704","phone":"(310) 510-2414","phoneLabel":"Museum","website":"https://www.catalinamuseum.org/","menuUrl":"https://www.catalinamuseum.org/tickets-hours","reserve":"https://www.catalinamuseum.org/tickets-hours","hours":[[[10,17]],[],[[10,17]],[[10,17]],[[10,17]],[[10,17]],[[10,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Adult admission","p":"$10","d":"Seniors, military & students $8 with ID"},{"n":"Children 15 & under","p":"Free","d":"Members also free"},{"n":"Special exhibitions","p":"","d":"Rotating gallery changes 3–4 times per year"}]}]},
  {"name":"Golf Gardens Miniature Golf","group":"do","kind":"place","cuisine":"Golf & Mini Golf","featured":false,"img":"","rating":"4.5","price":"$","tags":["Mini Golf","Family Fun","Garden Setting","Date Night","Cheap Fun"],"cats":["family","patio"],"desc":"An 18-hole, par-51 course tucked into a hillside garden one block off the beach — an island fixture for nearly 50 years. Last tee-off an hour before close; the course record is 41 if you're feeling brave.","address":"10 Island Plaza, Avalon, CA 90704","phone":"(310) 510-1200","phoneLabel":"Course","website":"https://www.visitcatalinaisland.com/things-to-do/golf-gardens-mini-golf","menuUrl":"https://www.visitcatalinaisland.com/things-to-do/golf-gardens-mini-golf","reserve":"","hours":[[[9,21]],[[9,21]],[[9,21]],[[9,21]],[[9,21]],[[9,21]],[[9,21]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Adult round (18 holes)","p":"$7","d":"Clubs and balls included; ~1 hour of play"},{"n":"Kids 8 & under","p":"$4","d":"Great starter course for little ones"},{"n":"Par 51 challenge","p":"","d":"Known in mini-golf circles as one of the most beautiful courses anywhere"}]}]},
  {"name":"Island Rentals Golf Carts","group":"do","kind":"place","cuisine":"Attraction","featured":false,"img":"","rating":"4.4","price":"$$","tags":["Golf Carts","Scenic Loop","Cash Only","Family Fun","No Reservations"],"cats":["family"],"desc":"Family-run since 1981 — grab a 4-seater and do the classic Mt. Ada / Wrigley Road scenic loop above town. Walk-up only, cash only, drivers 25+, and a strict 2-hour max; lines form by mid-morning in summer.","address":"125 Pebbly Beach Rd, Avalon, CA 90704","phone":"(310) 510-1456","phoneLabel":"Rentals","website":"https://www.lovecatalina.com/listing/island-rentals/39/","menuUrl":"https://www.lovecatalina.com/things-to-do/things-to-do-by-land/bikes-golf-carts/","reserve":"","hours":[[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Golf cart, first hour","p":"$70","d":"Seats 4; scenic loop takes about an hour"},{"n":"Second hour (prorated)","p":"$60","d":"2-hour maximum rental; cash only"},{"n":"Toddler/infant seats","p":"","d":"Available on request, limit 2 per cart; drivers 25+ with license & insurance"}]}]},
  {"name":"Catalina Island Golf Course","group":"do","kind":"place","cuisine":"Golf & Mini Golf","featured":false,"img":"","rating":"4.3","price":"$$","tags":["Historic Course","9 Holes","Est. 1892","Date Night"],"cats":[],"desc":"The oldest golf course west of the Mississippi (1892) — a 2,100-yard, par-32 executive 9 with two tee sets for 18-hole play. Quiet, walkable and gloriously untrendy.","address":"1 Country Club Dr, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://catalinagolfcourse.com/","menuUrl":"https://catalinagolfcourse.com/packages/","reserve":"https://catalinagolfcourse.com/","hours":[[[7,18]],[[7,18]],[[7,18]],[[7,18]],[[7,18]],[[7,18]],[[7,18]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"9-hole green fee","p":"$40","d":"Open to the public daily, year-round"},{"n":"9-hole package with rental clubs","p":"$60","d":"Green fee + clubs bundle"},{"n":"18-hole play","p":"","d":"Second tee set lets you replay the 9 as a full round"}]}]},
  {"name":"Two Harbors","group":"out","kind":"place","cuisine":"Beach & Shoreline","featured":false,"img":"","rating":"4.7","price":"$","tags":["Remote Village","Snorkeling","Camping","Hiking","Day Trip"],"cats":["waterfront"],"desc":"Catalina's one-restaurant, no-stoplight west-end outpost on a half-mile isthmus between two coves — the anti-Avalon. Ferry in via Catalina Express or hike the TCT; the Dive & Rec shop rents snorkel gear, paddleboards and bikes.","address":"1 Banning House Rd (Visitor Services), Two Harbors, CA 90704","phone":"(310) 510-4205","phoneLabel":"Visitor Services","website":"https://www.visitcatalinaisland.com/about-the-island/two-harbors","menuUrl":"https://www.lovecatalina.com/island-info/two-harbors/things-to-do/","reserve":"https://catalinaexpress.com/","hours":[[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Harbor Sands palapa & lounge rentals","p":"","d":"Beachside lounge chairs and palapas on the harbor"},{"n":"Dive & Recreation Shop rentals","p":"","d":"Snorkel sets, paddleboards, bikes, even frisbee golf"},{"n":"Harbor Reef Restaurant & Saloon","p":"","d":"The village's legendary buffalo-milk cocktail HQ; outdoor bar seasonal"}]}]},
  {"name":"Lovers Cove Marine Preserve","group":"out","kind":"place","cuisine":"Beach & Shoreline","featured":false,"img":"","rating":"4.6","price":"$","tags":["Best Snorkeling","Kelp Forest","Garibaldi","Free","No Sand"],"cats":["waterfront"],"desc":"The island's most reliable snorkel spot — a protected, surf-free cove of kelp forest teeming with garibaldi, opaleye and calico bass, a short walk from the ferry dock. Rocky entry, no facilities; rent gear nearby.","address":"400 Pebbly Beach Rd, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://www.californiabeaches.com/beach/lovers-cove-on-catalina-island/","menuUrl":"https://www.wetspotrentals.com/catalina-kayak-paddle-board-snorkel-gear-rentals","reserve":"","hours":[[[7,19]],[[7,19]],[[7,19]],[[7,19]],[[7,19]],[[7,19]],[[7,19]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Cove access","p":"Free","d":"State-protected marine preserve; no fishing or collecting"},{"n":"Snorkel gear nearby","p":"$15","d":"2-hr set from Wet Spot Rentals, 3 minutes away"},{"n":"Guided snorkel session (1 hr)","p":"$49","d":"Guided eco-snorkel with wetsuit, mask, fins included"}]}]},
  {"name":"South Beach & Middle Beach (Crescent Ave)","group":"out","kind":"place","cuisine":"Beach & Shoreline","featured":false,"img":"","rating":"4.4","price":"$","tags":["Town Beaches","Free","Family Fun","Green Pier","Calm Water"],"cats":["waterfront","family"],"desc":"Avalon's two free town beaches flanking the Green Pleasure Pier — calm harbor water, steps from every shop and taco on Crescent Ave. Small and towel-to-towel by 11am on summer weekends; come early for sand.","address":"Crescent Ave at Green Pleasure Pier, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://www.lovecatalina.com/things-to-do/","menuUrl":"","reserve":"","hours":[[[7,20]],[[7,20]],[[7,20]],[[7,20]],[[7,20]],[[7,20]],[[7,20]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Beach access","p":"Free","d":"Lifeguards seasonally; showers near the pier"},{"n":"Swim platform","p":"Free","d":"Float anchored off Middle Beach in summer"},{"n":"Pier-side rentals","p":"","d":"Umbrellas, floats and snacks steps away on Crescent Ave"}]}]},
  {"name":"Wet Spot Rentals","group":"out","kind":"place","cuisine":"Boating & Water","featured":false,"img":"","rating":"4.5","price":"$","tags":["Kayaks","SUP","Snorkel Gear","Budget Friendly","Since 1991"],"cats":["waterfront","family"],"desc":"The budget go-to by the Cabrillo Mole ferry dock, three minutes from Lovers Cove — rent one hour, get the second free. Kayaks, paddleboards, snorkel sets and wetsuits since '91.","address":"120 Pebbly Beach Rd, Avalon, CA 90704","phone":"(310) 510-2229","phoneLabel":"Rentals","website":"https://www.wetspotrentals.com/","menuUrl":"https://www.wetspotrentals.com/catalina-kayak-paddle-board-snorkel-gear-rentals","reserve":"https://www.wetspotrentals.com/","hours":[[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Single kayak","p":"$15/hr","d":"2nd hour free promo; doubles $22/hr"},{"n":"Snorkel gear set","p":"$15","d":"2 hours; half day $20, full day $30"},{"n":"Wetsuit rental","p":"$22","d":"2 hours; half day $30, full day $35"}]}]},
  {"name":"Descanso Beach Ocean Sports","group":"out","kind":"place","cuisine":"Boating & Water","featured":false,"img":"","rating":"4.6","price":"$$","tags":["Kayak Tours","SUP","Snorkeling","Frog Rock","Date Night"],"cats":["waterfront","family"],"desc":"Launch straight off Descanso Beach for kayak and SUP rentals or guided paddles toward Frog Rock — calm, clear water and no harbor traffic. Snorkel packages include wetsuit and vest.","address":"5 St Catherine Way (Descanso Beach), Avalon, CA 90704","phone":"(310) 510-1226","phoneLabel":"Beach Hut","website":"https://www.visitcatalinaisland.com/things-to-do","menuUrl":"https://www.yelp.com/biz/descanso-beach-ocean-sports-avalon-2","reserve":"","hours":[[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]],[[9,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Tandem kayak (1 hr)","p":"$35","d":"Singles and half/full-day rates also available"},{"n":"Snorkel package (1 hr)","p":"$20","d":"Wetsuit, snorkel set and life jacket included"},{"n":"Guided kayak eco-tours","p":"","d":"Ranger-style paddles along the leeward coast; book ahead in summer"}]}]},
  {"name":"Parasail Catalina","group":"out","kind":"place","cuisine":"Boating & Water","featured":false,"img":"","rating":"4.7","price":"$$$","tags":["Parasailing","800 ft Flights","Ocean Views","Date Night","Seasonal"],"cats":["waterfront"],"desc":"Soar up to 800 feet over Avalon Bay with the Casino shrinking below — tandem and triple flights available, and observers can ride along. Book the first trip of the day for $30 off per person; weather-dependent.","address":"105 Pebbly Beach Rd, Avalon, CA 90704","phone":"(310) 510-1777","phoneLabel":"Book Flights","website":"https://californiaparasail.com/catalina-island/","menuUrl":"https://californiaparasail.com/catalina-island/","reserve":"https://www.webreserv.com/parasailcatalinaca","hours":[[[8.5,17.5]],[[8.5,17.5]],[[8.5,17.5]],[[8.5,17.5]],[[8.5,17.5]],[[8.5,17.5]],[[8.5,17.5]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"800-ft flight","p":"$135","d":"Single, tandem or triple; ~10–12 min airborne"},{"n":"Early-bird special","p":"","d":"$30 off per person on the first trip of the day (8:30–11am window)"},{"n":"Observer seat","p":"","d":"Ride the boat without flying; cruise-ship specials offered"}]}]},
  {"name":"Wrigley Memorial & Botanic Garden","group":"out","kind":"place","cuisine":"Parks & Trails","featured":false,"img":"","rating":"4.6","price":"$","tags":["Botanic Garden","Endemic Plants","Memorial Views","Date Night","Quiet"],"cats":["patio"],"desc":"A 37-acre canyon garden of Catalina-endemic plants crowned by the grand Wrigley Memorial — climb it for the best free-with-admission view over Avalon. Free shuttle from the Conservancy Trailhead with your ticket.","address":"1400 Avalon Canyon Rd, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://catalinaconservancy.org/recreation/wrigley-memorial-and-botanic-garden/","menuUrl":"https://catalinaconservancy.org/recreation/wrigley-memorial-and-botanic-garden/","reserve":"","hours":[[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]],[[8,17]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Adult admission","p":"$16.84","d":"Includes taxes/fees; seniors 55+ & students $11.41"},{"n":"Children 5–12","p":"$8.15","d":"Under 5, active military & veterans, Conservancy members free"},{"n":"Trailhead shuttle","p":"Free","d":"Round-trip shuttle from the Trailhead Visitor Center with entry ticket"}]}]},
  {"name":"Trans-Catalina Trail","group":"out","kind":"place","cuisine":"Parks & Trails","featured":false,"img":"","rating":"4.8","price":"$","tags":["Backpacking","38.5 Miles","Free Permit","Bison Country","Epic Views"],"cats":[],"desc":"38.5 rugged miles from Avalon to Parsons Landing across the Conservancy's 42,000-acre preserve — most hikers take 3 days via Black Jack, Little Harbor and Two Harbors camps. Hiking permit is free; campsites book out months ahead.","address":"Trailhead Visitor Center, 708 Crescent Ave, Avalon, CA 90704","phone":"","phoneLabel":"","website":"https://catalinaconservancy.org/recreation/trans-catalina-trail/","menuUrl":"https://catalinaconservancy.org/recreation/trans-catalina-trail/","reserve":"https://www.visitcatalinaisland.com/stay/camping","hours":[[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Hiking permit","p":"Free","d":"Required — print at catalinaconservancy.org or pick up at Conservancy House (8:30am–4:30pm) or Two Harbors Visitor Center"},{"n":"Campsites en route","p":"","d":"Black Jack, Little Harbor, Two Harbors, Parsons Landing — reserve early"},{"n":"Day-hike sections","p":"Free","d":"Hermit Gulch–Divide loop is the classic Avalon taster"}]}]},
  {"name":"Hermit Gulch Trail & Campground","group":"out","kind":"place","cuisine":"Parks & Trails","featured":false,"img":"","rating":"4.4","price":"$","tags":["Day Hike","Camping","Canyon Views","TCT Access","Steep"],"cats":["family"],"desc":"Avalon's backyard trail — a steep 1.7-mile grunt from Avalon Canyon up to Divide Road, loopable with the TCT for knockout harbor views. The walk-in campground below is the only one near town.","address":"1201 Avalon Canyon Rd, Avalon, CA 90704","phone":"(310) 510-8368","phoneLabel":"Campground","website":"https://www.visitcatalinaisland.com/stay/camping","menuUrl":"https://www.hikespeak.com/campgrounds/hermit-gulch-catalina-island/","reserve":"https://www.visitcatalinaisland.com/stay/camping","hours":[[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]],[[6,20]]],"menu":[{"sec":"Prices & Highlights","items":[{"n":"Trail access","p":"Free","d":"Free Conservancy hiking permit required beyond the gate"},{"n":"Camping (per adult, per night)","p":"$25–$28","d":"Charged per person, not per site; kids $16–$19"},{"n":"Platform tent rental","p":"$60–$80","d":"Pre-set tents per night; prices vary by season/holiday"}]}]}
